import { mergeStyleSets } from '@kyokuya/core-util'
import { Link } from 'gatsby'
import React from 'react'

const GamesPage: React.FC = () => {
  return (
    <div className={classes.container}>
      <div className={classes.cards}>
        {routes.map((route, index) => (
          <Link key={index} className={classes.cardWrapper} to={route.url}>
            <span className={classes.card}>
              <span className={classes.cardContent} />
              <span className={classes.cardTitle}>{route.title}</span>
            </span>
          </Link>
        ))}
      </div>
    </div>
  )
}

export default GamesPage

const routes = [
  {
    title: 'gomoku',
    url: '/game/gomoku',
  },
  {
    title: 'sudoku',
    url: '/game/sudoku',
  },
]

const classes = mergeStyleSets({
  container: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    height: '100vh',
  },
  cards: {
    display: 'flex',
    flexWrap: 'wrap',
    alignItems: 'flex-start',
    maxWidth: '80%',
  },
  cardWrapper: {
    display: 'block',
    boxSizing: 'border-box',
    textDecoration: 'none',
  },
  card: {
    display: 'flex',
    flexDirection: 'column',
    boxSizing: 'border-box',
    height: 180,
    width: 120,
    border: '1px solid #ccc',
    borderRadius: 4,
    margin: '1rem',
  },
  cardTitle: {
    flex: '0 0 auto',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    height: '2rem',
    outline: 'none',
    textTransform: 'capitalize',
    '&:hover': {
      color: 'hsl(0deg, 0%, 80%)',
    },
    '&:active': {
      color: 'hsl(0deg, 0%, 95%)',
    },
  },
  cardContent: {
    flex: '1 1 auto',
  },
})
